-- ════════════════════════════════════════════════════════════════════════
--  QuestLog — difficulty for the Striver A-Z sheet (Easy/Medium/Hard)
-- ════════════════════════════════════════════════════════════════════════
--  Sourced from the takeuforward A2Z sheet difficulty labels (388 auto-
--  matched by title; 34 assigned by hand). Lets DSA problems award proper
--  10/15/25 XP instead of the flat default. Idempotent.
-- ════════════════════════════════════════════════════════════════════════

update public.sheet_items set difficulty = 'easy'
  where sheet_id = '00000000-0000-0000-0000-0000000000a2' and (order_index between 1 and 2 or order_index between 6 and 8 or order_index = 11 or order_index between 15 and 16 or order_index = 18 or order_index between 22 and 23 or order_index = 30 or order_index between 32 and 33 or order_index between 36 and 46 or order_index = 50 or order_index between 52 and 53 or order_index = 63 or order_index = 66 or order_index = 74 or order_index between 77 and 85 or order_index between 87 and 89 or order_index between 91 and 94 or order_index between 96 and 97 or order_index between 101 and 103 or order_index = 123 or order_index = 125 or order_index between 147 and 148 or order_index = 151 or order_index = 161 or order_index between 163 and 164 or order_index = 181 or order_index between 193 and 196 or order_index = 198 or order_index = 209 or order_index between 222 and 231 or order_index = 234 or order_index = 242 or order_index = 244 or order_index between 258 and 259 or order_index = 261 or order_index between 265 and 266 or order_index = 274 or order_index = 307 or order_index = 309 or order_index between 329 and 330 or order_index between 382 and 388 or order_index = 391 or order_index between 393 and 396 or order_index = 404 or order_index between 416 and 420 or order_index = 422);

update public.sheet_items set difficulty = 'medium'
  where sheet_id = '00000000-0000-0000-0000-0000000000a2' and (order_index between 3 and 5 or order_index between 9 and 10 or order_index between 12 and 13 or order_index = 19 or order_index = 21 or order_index between 24 and 29 or order_index = 31 or order_index between 47 and 49 or order_index between 56 and 57 or order_index between 68 and 70 or order_index = 72 or order_index between 75 and 76 or order_index = 86 or order_index = 90 or order_index = 95 or order_index between 99 and 100 or order_index between 104 and 118 or order_index = 122 or order_index = 124 or order_index between 126 and 130 or order_index = 135 or order_index between 137 and 141 or order_index = 143 or order_index between 149 and 150 or order_index between 152 and 160 or order_index = 162 or order_index between 166 and 170 or order_index = 173 or order_index between 177 and 180 or order_index between 182 and 185 or order_index between 189 and 192 or order_index between 199 and 201 or order_index between 203 and 205 or order_index between 207 and 208 or order_index between 210 and 220 or order_index between 232 and 233 or order_index between 235 and 238 or order_index between 240 and 241 or order_index = 243 or order_index between 245 and 247 or order_index between 249 and 250 or order_index between 253 and 254 or order_index = 260 or order_index between 262 and 264 or order_index between 267 and 269 or order_index = 271 or order_index between 275 and 284 or order_index between 286 and 292 or order_index = 305 or order_index = 323 or order_index = 328 or order_index = 332 or order_index between 334 and 336 or order_index = 341 or order_index = 344 or order_index = 347 or order_index between 357 and 360 or order_index between 362 and 364 or order_index between 373 and 374 or order_index between 389 and 390 or order_index = 392 or order_index between 397 and 402 or order_index = 411 or order_index = 414 or order_index = 421);

update public.sheet_items set difficulty = 'hard'
  where sheet_id = '00000000-0000-0000-0000-0000000000a2' and (order_index = 14 or order_index = 17 or order_index = 20 or order_index between 34 and 35 or order_index = 51 or order_index between 54 and 55 or order_index between 58 and 62 or order_index between 64 and 65 or order_index = 67 or order_index = 71 or order_index = 73 or order_index = 98 or order_index between 119 and 121 or order_index between 131 and 134 or order_index = 136 or order_index = 142 or order_index between 144 and 146 or order_index = 165 or order_index between 171 and 172 or order_index between 174 and 176 or order_index between 186 and 188 or order_index = 197 or order_index = 202 or order_index = 206 or order_index = 221 or order_index = 239 or order_index = 248 or order_index between 251 and 252 or order_index between 255 and 257 or order_index = 270 or order_index between 272 and 273 or order_index = 285 or order_index between 293 and 304 or order_index = 306 or order_index = 308 or order_index between 310 and 322 or order_index between 324 and 327 or order_index = 331 or order_index = 333 or order_index between 337 and 340 or order_index between 342 and 343 or order_index between 345 and 346 or order_index between 348 and 356 or order_index = 361 or order_index between 365 and 372 or order_index between 375 and 381 or order_index = 403 or order_index between 405 and 410 or order_index between 412 and 413 or order_index = 415);

-- Backfill existing quest items that came from this sheet (don't overwrite).
update public.quest_items qi
set difficulty = si.difficulty
from public.sheet_items si
where qi.source_item_id = si.id
  and qi.difficulty is null
  and si.difficulty is not null;
